solution.javascript:
import { test, expect } from '@playwright/test';

test('handle alerts and dialogs', async ({ page }) => {
  await page.goto('https://practice.expandtesting.com/js-dialogs');

  // Handle alert
  page.on('dialog', dialog => {
    expect(dialog.type()).toBe('alert');
    expect(dialog.message()).toContain('alert');
    dialog.accept();
  });
  await page.click('#js-alert');

  // Handle confirm - accept
  page.once('dialog', dialog => {
    expect(dialog.type()).toBe('confirm');
    dialog.accept();
  });
  await page.click('#js-confirm');
  await expect(page.locator('#dialog-response')).toContainText('OK');

  // Handle prompt with input
  page.once('dialog', dialog => {
    expect(dialog.type()).toBe('prompt');
    dialog.accept('Playwright Test');
  });
  await page.click('#js-prompt');
  await expect(page.locator('#dialog-response')).toContainText('Playwright Test');
});

